import { useEffect, useState } from "react";
import axios from "axios";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user"));

  const [workers, setWorkers] = useState([]);
  const [requests, setRequests] = useState([]);
  const [search, setSearch] = useState("");

  const [form, setForm] = useState({
    date: "",
    timings: []
  });

  // FETCH WORKERS
  useEffect(() => {
    fetchWorkers();
    fetchRequests();
  }, []);

  const fetchWorkers = async () => {
    try {
      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );
      setWorkers(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const fetchRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user._id}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // SEND REQUEST
  const sendRequest = async (worker) => {
    try {
      await axios.post(
        "http://localhost:5000/api/request/send",
        {
          customerId: user._id,
          customerName: user.name,

          labourId: worker._id,
          labourName: worker.name,

          workType: worker.skills?.[0] || "General Work",
          location: user.city,

          date: form.date || "Not selected",
          timings: form.timings || []
        }
      );

      alert("Request sent successfully!");
      fetchRequests();

    } catch (err) {
      alert("Failed to send request");
    }
  };

  // FILTER WORKERS
  const filteredWorkers = workers.filter((w) =>
    w.skills?.some(skill =>
      skill.toLowerCase().includes(search.toLowerCase())
    )
  );

  return (
    <div style={styles.page}>

      {/* TITLE */}
      <h2 style={styles.title}>Find Workers</h2>

      {/* SEARCH */}
      <input
        style={styles.search}
        placeholder="Search skill (Plumber, Electrician...)"
        onChange={(e) => setSearch(e.target.value)}
      />

      {/* WORKERS GRID */}
      <div style={styles.grid}>

        {filteredWorkers.map((worker) => (
          <div key={worker._id} style={styles.card}>

            <h3 style={{ marginBottom: "5px" }}>
              {worker.name}
            </h3>

            <p><b>Skills:</b> {worker.skills?.join(", ")}</p>
            <p><b>City:</b> {worker.city}</p>
            <p><b>Area:</b> {worker.area}</p>

            <input
              type="date"
              style={styles.input}
              onChange={(e) =>
                setForm({ ...form, date: e.target.value })
              }
            />

            <button
              style={styles.button}
              onClick={() => sendRequest(worker)}
            >
              Hire Worker
            </button>

          </div>
        ))}

      </div>

      {/* REQUEST STATUS SECTION */}
      <h2 style={styles.subTitle}>My Requests</h2>

      <div style={styles.grid}>

        {requests.map((req) => (
          <div key={req._id} style={styles.card}>

            <h3>{req.workType}</h3>

            <p><b>Labour:</b> {req.labourName}</p>
            <p><b>Date:</b> {req.date}</p>

            <p>
              <b>Status:</b>{" "}
              <span
                style={{
                  color:
                    req.status === "accepted"
                      ? "green"
                      : req.status === "rejected"
                      ? "red"
                      : "#f59e0b"
                }}
              >
                {req.status}
              </span>
            </p>

            <p>
              <b>Customer Decision:</b> {req.customerDecision}
            </p>

            {/* ⭐ RATING DISPLAY */}
            {req.isCompleted && (
              <div style={{ marginTop: "10px" }}>
                <p><b>Rating:</b> {"⭐".repeat(req.rating)}</p>
                <p>{req.review}</p>
              </div>
            )}

          </div>
        ))}

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f4f7fb",
    padding: "30px",
    fontFamily: "Arial"
  },

  title: {
    textAlign: "center",
    color: "#111827",
    marginBottom: "20px"
  },

  subTitle: {
    marginTop: "40px",
    textAlign: "center",
    color: "#111827"
  },

  search: {
    width: "100%",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    marginBottom: "20px",
    outline: "none"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
    gap: "20px"
  },

  card: {
    background: "white",
    padding: "20px",
    borderRadius: "14px",
    boxShadow: "0 6px 18px rgba(0,0,0,0.06)"
  },

  input: {
    width: "100%",
    padding: "10px",
    marginTop: "10px",
    borderRadius: "8px",
    border: "1px solid #d1d5db"
  },

  button: {
    width: "100%",
    marginTop: "12px",
    padding: "12px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer"
  }
};
